// Extract domain and prepare search context
const input = items[0].json.body || items[0].json;
let url = input.url || '';

// Clean URL to get domain
let domain = url;
try {
  if (!url.startsWith('http')) {
    url = 'https://' + url;
  }
  const urlObj = new URL(url);
  domain = urlObj.hostname.replace('www.', '');
} catch (e) {
  domain = url.replace(/^(https?:\/\/)?(www\.)?/, '').split('/')[0];
}

// Generate search queries for finding privacy policy
const searchQueries = [
  `site:${domain} privacy policy`,
  `${domain} GDPR privacy policy data protection`,
  `${domain} privacy notice terms`
];

return {
  json: {
    originalUrl: url,
    domain: domain,
    searchQueries: searchQueries,
    companyName: domain.split('.')[0].charAt(0).toUpperCase() + domain.split('.')[0].slice(1)
  }
};

parameters.text:
=Find the privacy policy URL for the company with domain: {{ $json.domain }}

Search strategies to try:
1. Check common paths: /privacy, /privacy-policy, /legal/privacy, /legal/privacy-policy
2. Look for links on the homepage footer
3. Search for "privacy policy" + company name

The company name appears to be: {{ $json.companyName }}

Your task: Return the MOST LIKELY URL where their privacy policy is located. If you cannot determine it, return the most standard path format.

Respond with ONLY a JSON object:
{
  "privacyPolicyUrl": "https://...",
  "confidence": "high/medium/low",
  "method": "description of how you found it"
}

parameters.jsCode:
// Parse the AI response to get the privacy policy URL
const aiOutput = items[0].json.output || items[0].json.text || '';
const domainData = $('2. Extract Domain & Prepare Search').first().json;

let policyUrl = '';
let confidence = 'low';

try {
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    policyUrl = parsed.privacyPolicyUrl || parsed.url || '';
    confidence = parsed.confidence || 'medium';
  }
} catch (e) {
  // Fallback: extract URL from text
  const urlMatch = aiOutput.match(/https?:\/\/[^\s"']+privacy[^\s"']*/i);
  if (urlMatch) {
    policyUrl = urlMatch[0];
    confidence = 'low';
  }
}

// If no URL found, try common patterns
if (!policyUrl) {
  policyUrl = `https://${domainData.domain}/privacy-policy`;
  confidence = 'fallback';
}

// Clean URLs
const urlsToTry = [
  policyUrl,
  `https://${domainData.domain}/privacy`,
  `https://${domainData.domain}/privacy-policy`,
  `https://${domainData.domain}/legal/privacy`
].filter((v, i, a) => a.indexOf(v) === i).slice(0, 3);

return {
  json: {
    ...domainData,
    policyUrl: policyUrl,
    urlsToTry: urlsToTry,
    confidence: confidence
  }
};

// Combine all fetched policy content
const allItems = items;
let combinedContent = '';
let successfulUrl = '';

for (const item of allItems) {
  if (item.json.data || item.json.body) {
    const content = item.json.data || item.json.body || '';
    if (content.length > 500) {
      combinedContent = content;
      successfulUrl = item.json.url || 'unknown';
      break;
    }
  }
}

// Extract text from HTML
if (combinedContent.includes('<')) {
  combinedContent = combinedContent
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Limit content length for LLM
const maxLength = 30000;
if (combinedContent.length > maxLength) {
  combinedContent = combinedContent.substring(0, maxLength) + '... [truncated]';
}

const domainData = $('4. Parse Policy URL Result').first().json;

return {
  json: {
    domain: domainData.domain,
    companyName: domainData.companyName,
    originalUrl: domainData.originalUrl,
    policyUrl: successfulUrl || domainData.policyUrl,
    policyContent: combinedContent,
    contentLength: combinedContent.length,
    fetchSuccess: combinedContent.length > 500
  }
};

// Parse the AI analysis response
const aiOutput = items[0].json.output || items[0].json.text || '';
const inputData = $('7. Combine & Clean Content').first().json;

let analysis = {};

try {
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  analysis = {
    error: 'Failed to parse analysis',
    raw: aiOutput.substring(0, 1000)
  };
}

// Ensure all expected fields exist
const result = {
  success: true,
  domain: inputData.domain,
  company_name: inputData.companyName,
  policy_url: inputData.policyUrl,
  dpo_email: analysis.dpo_email || null,
  company_address: analysis.company_address || null,
  data_collected: analysis.data_collected || [],
  retention_period: analysis.retention_period || 'Not specified',
  third_party_sharing: analysis.third_party_sharing || [],
  legal_basis: analysis.legal_basis || 'Not specified',
  request_methods: analysis.request_methods || {},
  summary: analysis.summary || 'Analysis completed',
  risk_score: analysis.risk_score || 50,
  gdpr_issues: analysis.gdpr_issues || [],
  analyzed_at: new Date().toISOString(),
  content_length: inputData.contentLength,
  raw_analysis: analysis
};

return { json: result };
